import java.util.*;
public class EnumSet {
    enum Suit { CLUBS, DIAMONDS, HEARTS, SPADES }
    public static void main(String[] args) {
        java.util.EnumSet<Suit> red = java.util.EnumSet.of(Suit.DIAMONDS, Suit.HEARTS);
        System.out.println(red.size());
        System.out.println(red.contains(Suit.HEARTS));
        System.out.println(red.contains(Suit.CLUBS));
    }
}
